1072	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-15 09:28:12.700904+00	2026-07-15 09:35:02.173053+00	410	{"7113": [["1", "Quản lý CSDL khảo sát", "Cần", null], ["2", "Chuẩn hóa dữ liệu", "Cần", null], ["3", "Danh mục dùng chung", "Cần", null], ["4", "Quản lý siêu dữ liệu (Metadata)", "Cần", null], ["5", "Đồng bộ dữ liệu", "Cần", null], ["6", "Lưu trữ dữ liệu lịch sử", "Cần", null], ["7", "Làm sạch dữ liệu", "Cần", null], ["8", "Kho dữ liệu khảo sát", "Cần", null], ["9", "Tra cứu dữ liệu", "Cần", null]], "7114": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7115": [["1", "Báo cáo tổng hợp khảo sát", "Cần", null], ["2", "Báo cáo theo đơn vị", "Cần", null], ["3", "Báo cáo theo địa bàn", "Cần", null], ["4", "Báo cáo theo thời gian", "Cần", null], ["5", "Báo cáo so sánh nhiều năm", "Cần", null], ["6", "Dashboard tổng hợp", "Cần", null], ["7", "Dashboard chi tiết", "Cần", null], ["8", "Dashboard điều hành", "Cần", null], ["9", "Biểu đồ trực quan", "Cần", null], ["10", "Xuất Excel/PDF/Word", "Cần", null], ["11", "Xuất dữ liệu mở", "Cần", null]], "7116": [["Hiệu năng hệ thống", "Cao"], ["Khả năng mở rộng", "Cao"], ["Tính sẵn sàng", "Cao"], ["An toàn thông tin", "Cao"], ["Sao lưu và phục hồi dữ liệu", "Cao"], ["Khả năng tích hợp", "Cao"], ["Khả năng khai thác trên thiết bị di động", "Cao"], ["Khả năng sử dụng", "Cao"], ["Khả năng bảo trì", "Cao"], ["Khả năng nâng cấp", "Cao"], ["Khả năng mở rộng tích hợp", "Cao"], ["Khả năng truy cập đa nền tảng(Web/Mobile/Tablet)", "Cao"], ["Tính thân thiện giao diện", "Cao"]], "7118": "Để phục vụ hiệu quả công tác quản lý và cải cách hành chính tại UBND phường Ô Chợ Dừa, các yêu cầu nghiệp vụ cần được ưu tiên hàng đầu bao gồm:\\nTự động hóa quy trình tổng hợp chỉ số CCHC: Đồng bộ dữ liệu từ các phần mềm chuyên ngành để tự động hóa việc tính điểm, đánh giá các tiêu chí CCHC của phường theo thời gian thực (real-time) thay vì phải tổng hợp thủ công định kỳ.\\nGiám sát thời gian xử lý hồ sơ hành chính công: Kiểm soát chặt chẽ quy trình tiếp nhận và thụ lý hồ sơ tại bộ phận Một cửa, tự động phát hiện các bước bị nghẽn hoặc có nguy cơ chậm muộn để kịp thời điều phối, đảm bảo tỷ lệ hồ sơ đúng hạn đạt trên 99%.\\n\\nQuản lý và tái sử dụng kho kết quả số hóa: Lưu trữ tập trung các kết quả giải quyết TTHC (đã ký số) thuộc thẩm quyền cấp phường để cán bộ các bộ phận khác nhau có thể tra cứu và tái sử dụng trực tiếp, giảm phiền hà cho người dân khi nộp hồ sơ trực tuyến.\\nĐo lường sự hài lòng của công dân (SIPAS) gắn liền với từng hồ sơ: Tự động gửi link khảo sát hoặc hiển thị bảng đánh giá ngay sau khi trả kết quả TTHC để thu thập phản hồi thực chất từ người dân về tinh thần phục vụ của cán bộ.", "7119": "Nhằm nhanh chóng đưa hệ thống đi vào hoạt động thực tế và mang lại hiệu quả tức thì, các chức năng cần được tập trung triển khai trước bao gồm:\\nChức năng Dashboard Giám sát tiến độ giải quyết hồ sơ trực tuyến: Trực quan hóa số liệu hồ sơ đang tiếp nhận, đang xử lý, sắp hạn và quá hạn tại bộ phận Một cửa theo từng lĩnh vực chuyên môn (Hộ tịch, Tư pháp, Địa chính - Xây dựng, Lao động - Thương binh & Xã hội).\\nChức năng Kết xuất Báo cáo CCHC tự động: Cho phép người dùng xuất nhanh các báo cáo thống kê định kỳ (tuần, tháng, quý) về tình hình giải quyết TTHC, tỷ lệ dịch vụ công trực tuyến toàn trình/một phần đúng theo biểu mẫu quy định của Quận và Thành phố.\\nChức năng Cảnh báo chậm muộn hồ sơ tự động: Tự động gửi thông báo nhắc nhở (qua hệ thống, SMS hoặc ứng dụng điều hành) đến cán bộ thụ lý và lãnh đạo UBND phường khi hồ sơ còn 04 giờ làm việc là đến hạn mà chưa có kết quả phê duyệt.", "7120": "Để việc xây dựng và đưa hệ thống mới vào vận hành thực tế đạt hiệu quả cao nhất, tránh lãng phí nguồn lực, UBND phường kính đề xuất một số nội dung cần được nghiên cứu và làm rõ thêm như sau:\\nLàm rõ phương án kỹ thuật kết nối và đồng bộ dữ liệu thời gian thực (Real-time Sync): Nghiên cứu giải pháp kết nối API mượt mà giữa hệ thống mới với các cơ sở dữ liệu chuyên ngành cấp Bộ (như Cơ sở dữ liệu Hộ tịch của Bộ Tư pháp, Cơ sở dữ liệu Đất đai) và Hệ thống thông tin giải quyết TTHC của Thành phố để đảm bảo dữ liệu không bị lệch dòng, không bắt cán bộ phải nhập liệu thủ công \\"hai vai\\".\\nNghiên cứu cơ chế bảo mật và phân quyền khai thác dữ liệu số hóa: Làm rõ quy trình phân quyền truy cập, chia sẻ thông tin giữa các bộ phận chuyên môn trong UBND phường và các đơn vị liên thông (như Công an phường, Chi cục Thuế) để vừa phục vụ tốt công tác nghiệp vụ phối hợp, vừa bảo mật tuyệt đối dữ liệu cá nhân của công dân theo Nghị định số 13/2023/NĐ-CP.\\nXác định rõ giá trị pháp lý của kết quả số hóa dùng chung: Nghiên cứu và hướng dẫn cụ thể về quy trình phê duyệt, ký số và công nhận giá trị pháp lý lâu dài của các loại giấy tờ đã được số hóa lưu kho. Làm rõ trường hợp nào cán bộ Một cửa được phép sử dụng hoàn toàn bản điện tử trong kho dùng chung để thay thế cho việc đối chiếu bản chính giấy của người dân.\\nĐánh giá mức độ tương thích và khả năng nâng cấp hạ tầng: Nghiên cứu kỹ khả năng đáp ứng của hệ thống khi chạy trên các cấu hình máy tính văn phòng cũ hiện có tại cấp phường, đồng thời làm rõ phương án dự phòng (Backup) dữ liệu khi xảy ra sự cố nghẽn mạng hoặc mất kết nối máy chủ tổng.", "7121": [["1", "Xây dựng phân hệ Giám sát, Cảnh báo sớm tiến độ giải quyết hồ sơ thủ tục hành chính theo thời gian thực (Real-time Dashboard) giúp ngăn ngừa tình trạng trễ hẹn hồ sơ tại bộ phận Một cửa.", "Cao"], ["2", "Hoàn thiện kết nối API liên thông đồng bộ dữ liệu giữa hệ thống mới với Hệ thống thông tin giải quyết TTHC của Thành phố và các cơ sở dữ liệu chuyên ngành cấp Bộ (đặc biệt là dữ liệu dân cư, hộ tịch).", "Cao"], ["3", "Xây dựng kho số hóa dùng chung và tính năng tự động hóa báo cáo CCHC định kỳ nhằm giảm tải áp lực thống kê thủ công cho cán bộ chuyên trách tại địa phương.", "Cao"]], "7124": "0932230889", "7125": "Ô Chợ Dừa", "7126": "ks2_ochodua", "7127": "Chuyên viên", "7128": [["1", "Quản lý kế hoạch điều tra xã hội học", "Đã có nhưng cần nâng cấp", "TB", ""], ["2", "Quản lý kế hoạch khảo sát SIPAS", "Đã có nhưng cần nâng cấp", "TB", ""], ["3", "Quản lý danh mục khảo sát", "Đã có nhưng cần nâng cấp", "TB", ""], ["4", "Quản lý bộ câu hỏi khảo sát", "Đã có nhưng cần nâng cấp", "TB", ""], ["5", "Quản lý biểu mẫu khảo sát", "Đã có nhưng cần nâng cấp", "TB", ""], ["6", "Quản lý đối tượng khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["7", "Quản lý danh sách mẫu khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["8", "Quản lý hồ sơ khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["9", "Theo dõi tiến độ khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["10", "Quản lý kết quả khảo sát", "Đã có nhưng cần nâng cấp", "TB", ""], ["11", "Tổng hợp và tính toán chỉ số", "Đã có nhưng cần nâng cấp", "TB", ""], ["12", "Báo cáo thống kê", "Đã có nhưng cần nâng cấp", "TB", ""], ["13", "Bảng điều khiển (Dashboard)", "Đã có nhưng cần nâng cấp", "TB", ""]], "7129": [["1", "Quản lý người sử dụng", "Cần", null, null], ["2", "Quản lý phân quyền", "Cần", null, null], ["3", "Quản lý kế hoạch khảo sát", "Cần", null, null], ["4", "Quản lý danh mục khảo sát", "Cần", null, null], ["5", "Quản lý bộ câu hỏi", "Cần", null, null], ["6", "Quản lý biểu mẫu", "Cần", null, null], ["7", "Quản lý đối tượng khảo sát", "Cần", null, null], ["8", "Quản lý danh sách mẫu khảo sát", "Cần", null, null], ["9", "Thu thập khảo sát trực tuyến", "Cần", null, null], ["10", "Thu thập khảo sát trên thiết bị di động", "Cần", null, null], ["11", "Kiểm tra dữ liệu", "Cần", null, null], ["12", "Làm sạch dữ liệu", "Cần", null, null], ["13", "Tổng hợp kết quả", "Cần", null, null], ["14", "Phân tích dữ liệu", "Cần", null, null], ["15", "Quản