 đồng thời phải triển khai nhiều nhiệm vụ về cải cách hành chính, chuyển đổi số, giải quyết thủ tục hành chính và các nhiệm vụ đột xuất khác; vì vậy, thời gian dành cho công tác tuyên truyền, hướng dẫn và theo dõi việc thực hiện khảo sát còn hạn chế", "7279": "tập trung hoàn thiện bộ câu hỏi sát với thực tế, nắm bắt được tình hình thực tế tại các cơ quan đơn vị.", "email": "", "phone": "", "agency": "Phúc Sơn", "position": "", "full_name": "ks2_phucson", "department": "Phúc Sơn", "organization": "Phúc Sơn"}	f	\N	f	f	2026-07-14 07:01:18.952553+00	547	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	submitted
