andinh", "department": "Vân Đình", "organization": "Vân Đình"}	f	\N	f	f	2026-07-15 06:33:53.025836+00	550	16	{"sec_mrd3lxb1_4sre5": 100, "sec_mrd3mk79_mf9ln": 0, "sec_mrd3y4v6_12wu0": 100, "sec_mrd3y4v6_1oowr": 100, "sec_mrd4dtgl_a57uj": 100, "sec_mrd4dtgl_kpp08": 100, "sec_mrd4dtgl_qprnt": 100}	submitted
