g"]], "type": "grid"}, "7214": {"data": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "7215": {"data": [[null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7216": {"data": [[null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7217": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7218": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7219": {"data": [[null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"]], "type": "grid"}, "7220": {"data": [[null, "Cao", null, null], [null, null, "Trung bình", null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "7222": "Hạ tầng công nghệ thông tin chưa đồng bộ, một số thiết bị máy tính, máy in, thiết bị mạng đã được trang bị từ nhiều năm trước, cấu hình thấp, thường xuyên phát sinh lỗi, ảnh hưởng đến hiệu quả xử lý công việc.\\nSố lượng hệ thống, phần mềm sử dụng ngày càng nhiều, do các bộ, ngành và Thành phố triển khai nhưng chưa được tích hợp hoàn toàn; cán bộ phải thao tác trên nhiều nền tảng khác nhau, dẫn đến mất nhiều thời gian và dễ phát sinh sai sót.\\nĐường truyền Internet và mạng truyền số liệu chuyên dùng có thời điểm chưa ổn định, đặc biệt khi nhiều cán bộ truy cập đồng thời hoặc trong thời gian cao điểm, ảnh hưởng đến việc giải quyết thủ tục hành chính và xử lý văn bản điện tử.\\nViệc phân quyền, cấp tài khoản, điều chỉnh thông tin người dùng trên một số hệ thống còn chậm, nhất là sau khi sắp xếp đơn vị hành chính, thay đổi tổ chức bộ máy và cán bộ, làm ảnh hưởng đến quá trình khai thác, sử dụng phần mềm.\\nMột số hệ thống thông tin thường xuyên bảo trì, nâng cấp hoặc phát sinh lỗi kỹ thuật, thời gian khắc phục phụ thuộc đơn vị quản lý hệ thống, cấp xã không chủ động xử lý được.\\nNguồn nhân lực công nghệ thông tin tại cấp xã còn mỏng, hầu hết chỉ có 01 cán bộ phụ trách đồng thời nhiều lĩnh vực như công nghệ thông tin, chuyển đổi số, an toàn thông tin, Đề án 06, hỗ trợ người dân và cán bộ sử dụng phần mềm, nên khối lượng công việc rất lớn.\\nKinh phí dành cho duy trì, bảo trì, nâng cấp hệ thống công nghệ thông tin còn hạn chế, chưa đáp ứng yêu cầu thay thế thiết bị xuống cấp, bổ sung thiết bị bảo mật và triển khai các giải pháp bảo đảm an toàn thông tin.\\nNguy cơ mất an toàn thông tin, an ninh mạng ngày càng gia tăng, trong khi việc đầu tư các giải pháp giám sát, phòng chống mã độc, tường lửa, sao lưu dữ liệu còn chưa đầy đủ.\\nCông tác hỗ trợ kỹ thuật từ các đơn vị quản lý hệ thống đôi khi chưa kịp thời; việc tiếp nhận, xử lý phản ánh, khắc phục sự cố còn mất nhiều thời gian, ảnh hưởng đến tiến độ giải quyết công việc.\\nTrình độ ứng dụng công nghệ thông tin của một bộ phận cán bộ và người dân chưa đồng đều, vẫn cần nhiều thời gian để hướng dẫn sử dụng dịch vụ công trực tuyến, chữ ký số và các nền tảng số.", "7223": "Tăng cường tích hợp, liên thông, đồng bộ dữ liệu giữa các hệ thống thông tin dùng chung.\\nRút ngắn thời gian cấp tài khoản, phân quyền và hỗ trợ kỹ thuật đối với các hệ thống dùng chung.\\nTổ chức các lớp đào tạo, tập huấn chuyên sâu về công nghệ thông tin, an toàn thông tin và chuyển đổi số cho cán bộ cấp xã.\\nBố trí đủ kinh phí cho công tác duy trì, vận hành, bảo trì và bảo đảm an toàn thông tin; đồng thời tăng cường đầu tư các giải pháp bảo mật và sao lưu dữ liệu.\\nNâng cao chất lượng đường truyền mạng truyền số liệu chuyên dùng và Internet để đáp ứng yêu cầu xử lý công việc trên môi trường số.", "7224": {"data": [[null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"], [null, null, null, "Phù Đổng"]], "type": "grid"}, "email": "", "phone": "", "agency": "Phù Đổng", "position": "", "full_name": "ks2_phudong", "department": "Phù Đổng", "organization": "Phù Đổng"}	f	\N	f	f	2026-07-15 03:14:01.328709+00	521	18	{"sec_mrd51u8k_s7xvx": 0, "sec_mrd52i20_bxs8q": 100, "sec_mrd589py_n4ccb": 100, "sec_mrd58wv7_h9r0m": 100, "sec_mrd5h8uk_83ljt": 100, "sec_mrd5h8uk_lb1ld": 100, "sec_mrd5h8uk_q8t9f": 100, "sec_mrd5h8uk_zlvj1": 100, "sec_mrd5h8uk_znbx8": 100, "sec_mrd5hvzu_sb784": 100, "sec_mrd5hvzv_7jcz3": 100, "sec_mrd5hvzv_a4wue": 100, "sec_mrd5hvzv_ae5ra": 100, "sec_mrd5hvzv_vsvm8": 100, "sec_mrd5hvzv_ztdcy": 100, "