ata": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, "Có", null]], "type": "grid"}, "7215": {"data": [[null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7216": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7217": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null]], "type": "grid"}, "7218": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7219": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"]], "type": "grid"}, "7220": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "7221": "Cần nâng cấp", "7222": "Số lượng hệ thống thông tin, phần mềm phục vụ công tác chỉ đạo, điều hành và giải quyết thủ tục hành chính ngày càng nhiều nhưng nguồn nhân lực chuyên trách công nghệ thông tin tại cấp xã còn mỏng, chủ yếu kiêm nhiệm nên gặp khó khăn trong việc quản trị, giám sát, xử lý sự cố và hỗ trợ người sử dụng. Một số hệ thống chưa được liên thông, đồng bộ dữ liệu hoàn toàn, dẫn đến việc phải nhập liệu nhiều lần, làm tăng khối lượng công việc của cán bộ, công chức.\\n\\nNgoài ra, kinh phí dành cho duy trì, nâng cấp hạ tầng, bảo trì hệ thống và bảo đảm an toàn thông tin còn hạn chế, trong khi yêu cầu về chuyển đổi số, bảo mật và an toàn dữ liệu ngày càng cao. Điều này ảnh hưởng nhất định đến việc duy trì hoạt động ổn định, liên tục của các hệ thống công nghệ thông tin và triển khai hiệu quả các nhiệm vụ chuyển đổi số tại địa phương.", "7223": "- Đề nghị tiếp tục hoàn thiện chức năng các hệ thống thông tin theo hướng đồng bộ, liên thông, chia sẻ dữ liệu giữa các phần mềm; giảm việc nhập liệu trùng lặp, nâng cao hiệu quả khai thác và sử dụng dữ liệu.\\n- Đề nghị tăng cường công tác giám sát, cảnh báo và bảo đảm an toàn, an ninh thông tin; thực hiện sao lưu dữ liệu định kỳ, có phương án dự phòng nhằm bảo đảm hoạt động liên tục của các hệ thống.\\n- Đề nghị xây dựng và duy trì đầu mối hỗ trợ kỹ thuật trực tuyến, tiếp nhận và xử lý kịp thời các phản ánh, vướng mắc của cơ sở; rút ngắn thời gian xử lý sự cố để không ảnh hưởng đến hoạt động chuyên môn.\\n\\n6. Đề nghị tổ chức các lớp tập huấn, hướng dẫn sử dụng khi triển khai các phiên bản hoặc tính năng mới của hệ thống; đồng thời ban hành đầy đủ tài liệu hướng dẫn để các đơn vị thuận tiện trong quá trình khai thác, sử dụng.", "7224": {"data": [[null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null], [null, null, "Không", null]], "type": "grid"}}	f	\N	f	f	2026-07-14 10:38:13.001739+00	\N	18	{"sec_mrd51u8k_s7xvx": 0, "sec_mrd52i20_bxs8q": 100, "sec_mrd589py_n4ccb": 100, "sec_mrd58wv7_h9r0m": 100, "sec_mrd5h8uk_83ljt": 100, "sec_mrd5h8uk_lb1ld": 100, "sec_mrd5h8uk_q8t9f": 100, "sec_mrd5h8uk_zlvj1": 100, "sec_mrd5h8uk_znbx8": 100, "sec_mrd5hvzu_sb784": 100, "sec_mrd5hvzv_7jcz3": 100, "sec_mrd5hvzv_a4wue": 100, "sec_mrd5hvzv_ae5ra": 100, "sec_mrd5hvzv_vsvm8": 100, "sec_mrd5hvzv_ztdcy": 100, "sec_mrd5ij53_k401z": 100, "sec_mrd5ij53_lxnd3": 100}	submitted
