"}, "7222": "Chưa có tiêu chuẩn về công tác quản lý, vận hành hệ thống CNTT cấp xã", "7223": "Đề nghị thành phố ra bộ tiêu chí, tiêu chuẩn chung đối với hệ thống", "7224": {"data": [[null, "Có", null, "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, null, null, "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, "Có", null, "Nam Phù"], [null, null, "Không", "Nam Phù"], [null, null, "Không", "Nam Phù"]], "type": "grid"}, "email": "", "phone": "", "agency": "Nam Phù", "position": "", "full_name": "ks2_namphu", "department": "Nam Phù", "organization": "Nam Phù"}	f	\N	f	f	2026-07-15 08:09:57.648917+00	567	18	{"sec_mrd51u8k_s7xvx": 0, "sec_mrd52i20_bxs8q": 100, "sec_mrd589py_n4ccb": 100, "sec_mrd58wv7_h9r0m": 100, "sec_mrd5h8uk_83ljt": 100, "sec_mrd5h8uk_lb1ld": 100, "sec_mrd5h8uk_q8t9f": 100, "sec_mrd5h8uk_zlvj1": 100, "sec_mrd5h8uk_znbx8": 100, "sec_mrd5hvzu_sb784": 100, "sec_mrd5hvzv_7jcz3": 100, "sec_mrd5hvzv_a4wue": 100, "sec_mrd5hvzv_ae5ra": 100, "sec_mrd5hvzv_vsvm8": 100, "sec_mrd5hvzv_ztdcy": 100, "sec_mrd5ij53_k401z": 100, "sec_mrd5ij53_lxnd3": 100}	submitted
472	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 09:04:31.75224+00	2026-07-14 09:56:27.770538+00	1698	{"7113": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "7114": {"data": [[null, "Cần", null, "Cần Kết nối qua Nền tảng tích hợp, chia sẻ dữ liệu của Thành phố để chia sẻ dữ liệu giữa các hệ thống."], [null, "Cần", null, "Thực hiện khi có yêu cầu kết nối với các hệ thống, cơ sở dữ liệu của Trung ương thông qua Nền tảng tích hợp, chia sẻ dữ liệu quốc gia."], [null, "Cần", null, "Cung cấp và sử dụng API để tích hợp, trao đổi dữ liệu với các hệ thống liên quan."], [null, "Cần", null, "Khai thác các danh mục dùng chung (đơn vị hành chính, cơ quan, cán bộ...) nhằm tránh nhập liệu trùng lặp."], [null, "Cần", null, "Kết nối theo quy định và phân quyền để khai thác thông tin phục vụ khảo sát, hạn chế nhập liệu thủ công."], [null, "Cần", null, "Đồng bộ, tổng hợp kết quả khảo sát DDCI phục vụ đánh giá và báo cáo."], [null, "Cần", null, "Tự động đồng bộ dữ liệu khảo sát giữa các cấp và các hệ thống liên quan theo thời gian thực hoặc định kỳ."], [null, "Cần", null, "Phục vụ ban hành kế hoạch, quyết định, báo cáo và trao đổi văn bản điện tử."], [null, "Cần", null, "Khai thác danh sách tổ chức, cá nhân đã thực hiện thủ tục hành chính để phục vụ khảo sát SIPAS."], [null, "Cần", null, "Sử dụng tài khoản đăng nhập tập trung (SSO) để bảo đảm an toàn, thuận tiện trong quản lý người dùng."], [null, "Cần", null, "Tự động chia sẻ số liệu, giảm việc lập báo cáo thủ công và phục vụ công tác chỉ đạo, điều hành."]], "type": "grid"}, "7116": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Thấp", "Cao", "Cao", "Cao", "Cao"]], "7118": "Ưu tiên xây dựng hệ thống quản lý thống nhất toàn bộ quy trình điều tra xã hội học, khảo sát SIPAS và DDCI từ lập kế hoạch, quản lý đối tượng khảo sát, thiết kế bộ câu hỏi, thu thập dữ liệu trực tuyến, theo dõi tiến độ, tổng hợp kết quả, tính toán chỉ số và xây dựng báo cáo thống kê. Hệ thống cần kết nối, chia sẻ dữ liệu với Hệ thống thông tin giải quyết thủ tục hành chính, Hệ thống quản lý văn bản và các cơ sở dữ liệu dùng chung để giảm nhập liệu thủ công, nâng cao chất lượng dữ liệu.", "7119": "Quản lý kế hoạch khảo sát.\\nQuản lý người dùng và phân quyền.\\nQuản lý đối tượng khảo sát và danh sách mẫu khảo sát.\\nThu thập khảo sát trực tuyến và trên thiết bị di động.\\nTheo dõi tiến độ thực hiện khảo sát.\\nKiểm tra, làm sạch dữ liệu.\\nTổng hợp kết quả và tự động tính toán chỉ số.\\nDashboard điều hành và báo cáo thống kê.\\nKết nối với Hệ thống thông tin giải quyết thủ tục hành chính, Hệ thống quản lý văn bản và các cơ sở dữ liệu dùng chung.", "7120": "Làm rõ phạm vi kết nối, chia sẻ dữ liệu với các cơ sở dữ liệu quốc gia và cơ sở dữ liệu dùng chung của Thành phố theo quy định về phân quyền và bảo mật.\\nNghiên cứu phương án xác thực người tham gia khảo sát nhằm bảo đảm mỗi đối tượng chỉ tham gia một lần, tránh trùng lặp kết quả.\\nXây dựng tiêu chuẩn chung về bộ câu hỏi, phương pháp chọn mẫu, quy trình tổng hợp và tính toán chỉ số để áp dụng thống nhất trên toàn Thành phố.\\nNghiên cứu ứng dụng trí tuệ nhân tạo (AI) trong phân tích dữ liệu khảo sát, phát hiện dữ liệu bất thường, hỗ trợ tổng hợp báo cáo và dự báo xu hướng.\\nHoàn thiện cơ chế bảo đảm an toàn thông tin, lưu trữ dữ liệu lâu dài và sao lưu, phục hồi dữ liệu khi xảy ra sự cố.", "7121": [["Cao", "Cao", "Cao"]], "7123": "Đề nghị bổ sung thêm sau khảo sát.", "7124": "hoangthoadongmy@gmail.com/0904827538", "7125": "Nam Phù", "7126": "ks2_namphu", "7127": "Chuyên viên", "7128": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "7129": [["Cao", "Cao", "Cao", "TB", "Cao", "TB", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "TB", "TB", "TB", "Cao", "TB", "Thấp", "Thấp", "Cao", "TB", "Cao"]], "email": "", "phone": "", "agency": "Nam Phù", "position": "", "full_name": "ks2_namphu", "department": "Nam Phù", "organization": "Nam Phù"}	f	\N	f	f	2026-07-14 09:04:31.752296+00	567	21	{"sec_mrji32jc_02myx": 100, "sec_mrji3pol_08ygj": 100, "sec_mrji3pol_kjxj5": 100, "sec_mrji3pom_xwahu": 100, "sec_mrji4ctm_06kdb": 0, "sec_mrji4ctm_gtanp": 100, "sec_mrji4ctm_w2j5m": 100, "sec_mrji4zz8_b0vue": 100, "sec_mrji4zz8_eyyqa": 0, "sec_mrji4zz8_qvwvf": 100}	submitted
