mềm quản lý văn bản và áp dụng chữ ký số.\\n- Truyền thông cơ sở: Ứng dụng đài truyền thanh thông minh và các kênh trực tuyến (Zalo OA, cổng thông tin) để truyền tải chính sách và tiếp nhận phản ánh kịp thời.\\n-Đảm bảo an toàn thông tin: Trang bị giải pháp bảo mật để đảm bảo an toàn thông tin tại cơ quan", "7119": "-Đảm bảo an toàn thông tin: Trang bị giải pháp bảo mật để đảm bảo an toàn thông tin tại cơ quan", "7120": "- Quản lý điều hành nội bộ: Số hóa quy trình làm việc, loại bỏ giấy tờ truyền thống thông qua phần mềm quản lý văn bản", "7121": [["1", "Cải tạo, mua sắm thiết bị cho hệ thống mạng LAN tại trụ sở HĐND và UBND", "Cao"], ["2", "Nâng cấp, thay thế các máy tính đã cũ, được cấp từ lâu, cấu  hình thấp", "cao"], ["3", "Đảm bảo an toàn cho hệ thống thông tin tại UBND xã", "Cao"]], "7124": "nguyenthithanhnha_phucson@hanoi.gov.vn", "7125": "Phúc Sơn", "7126": "ks2_phucson", "7127": "Chuyên viên Văn phòng HĐND-UBND xã", "7128": [["1", "Quản lý kế hoạch điều tra xã hội học", "Đang thực hiện thủ công", "Cao", ""], ["2", "Quản lý kế hoạch khảo sát SIPAS", "Đang thực hiện thủ công", "Cao", ""], ["3", "Quản lý danh mục khảo sát", "Đang thực hiện thủ công", "Cao", ""], ["4", "Quản lý bộ câu hỏi khảo sát", "Đang thực hiện thủ công", "Cao", ""], ["5", "Quản lý biểu mẫu khảo sát", "Đang thực hiện thủ công", "Cao", ""], ["6", "Quản lý đối tượng khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["7", "Quản lý danh sách mẫu khảo sát", "Đang thực hiện thủ công", "Cao", ""], ["8", "Quản lý hồ sơ khảo sát", "Đang thực hiện thủ công", "Cao", ""], ["9", "Theo dõi tiến độ khảo sát", "Đã có nhưng cần nâng cấp", "Cao", ""], ["10", "Quản lý kết quả khảo sát", "Đã có và đáp ứng tốt", "Cao", ""], ["11", "Tổng hợp và tính toán chỉ số", "Đã có nhưng cần nâng cấp", "Cao", ""], ["12", "Báo cáo thống kê", "Đang thực hiện thủ công", "Cao", ""], ["13", "Bảng điều khiển (Dashboard)", "Đã có và đáp ứng tốt", "Cao", ""]], "7129": [["1", "Quản lý người sử dụng", "Cần", null, "Cao"], ["2", "Qu