ó", null], [null, "Có", null]], "type": "grid"}, "7215": {"data": [[null, "Có", null], [null, "Có", null], [null, null, null], [null, null, null], [null, null, null], [null, null, null], [null, null, null], [null, null, null], [null, null, null], [null, null, null], [null, null, null]], "type": "grid"}, "7216": {"data": [[null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7217": {"data": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "7218": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, null, null, "Không có ý kiến"], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, null, null, "Không có ý kiến"], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, null, null, "Không có ý kiến"], [null, null, null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7219": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, null, null], [null, null, null], [null, "Cần", null], [null, null, "Không cần"], [null, "Cần", null]], "type": "grid"}, "7220": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, null, "Trung bình", null], [null, null, "Trung bình", null], [null, null, "Trung bình", null], [null, null, "Trung bình", null], [null, null, "Trung bình", null]], "type": "grid"}, "7222": "Trong quá trình quản lý, khai thác và vận hành các hệ thống công nghệ thông tin dùng chung, vẫn còn phát sinh một số khó khăn, vướng mắc. Cụ thể, một số thời điểm hệ thống hoạt động chưa ổn định, tốc độ xử lý chậm, xảy ra tình trạng quá tải hoặc gián đoạn, ảnh hưởng đến việc tiếp nhận, giải quyết thủ tục hành chính và xử lý hồ sơ trên môi trường điện tử. Việc đồng bộ, liên thông dữ liệu giữa một số hệ thống, phần mềm chuyên ngành chưa thực sự thông suốt, dẫn đến cán bộ, công chức phải thực hiện thao tác nhập liệu trên nhiều hệ thống, làm tăng thời gian xử lý công việc.\\n\\nBên cạnh đó, việc cập nhật, nâng cấp phần mềm đôi khi chưa được thông báo kịp thời, phát sinh lỗi kỹ thuật hoặc thay đổi chức năng làm ảnh hưởng đến quá trình sử dụng của cán bộ, công chức. Công tác hỗ trợ kỹ thuật trong một số trường hợp còn chậm, thời gian xử lý sự cố kéo dài, nhất là vào các thời điểm cao điểm giải quyết hồ sơ hành chính. Ngoài ra, hạ tầng công nghệ thông tin tại cơ sở mặc dù đã được quan tâm đầu tư nhưng vẫn chưa đáp ứng đầy đủ yêu cầu vận hành đồng thời nhiều hệ thống, phần mềm dùng chung, ảnh hưởng đến hiệu quả thực hiện nhiệm vụ và tiến trình chuyển đổi số.", "7223": "Đề nghị cơ quan có thẩm quyền tiếp tục nâng cấp, hoàn thiện hệ thống công nghệ thông tin dùng chung, bảo đảm hoạt động ổn định, thông suốt và đồng bộ giữa các nền tảng, hạn chế tình trạng quá tải, gián đoạn hoặc phát sinh lỗi trong quá trình khai thác, sử dụng. Đồng thời, thường xuyên bảo trì, tối ưu hiệu năng hệ thống, nâng cao tốc độ xử lý, tăng cường khả năng liên thông, chia sẻ dữ liệu giữa các phần mềm chuyên ngành; kịp thời hỗ trợ kỹ thuật, khắc phục sự cố để không ảnh hưởng đến tiến độ giải quyết công việc, nhất là việc tiếp nhận, giải quyết thủ tục hành chính và cung cấp dịch vụ công trực tuyến cho người dân, doanh nghiệp.", "7224": {"data": [[null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn Đồng"], [null, null, null, "Sơn