423	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36 Edg/150.0.0.0	2026-07-14 08:34:05.822227+00	2026-07-14 08:42:16.995032+00	491	{"7113": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "7114": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7116": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "7118": "Ưu tiên bổ sung các chức năng thống kê kết quả khảo sát theo thời gian thực; tối ưu giao diện và quy trình tham gia khảo sát qua mã QR, đường liên kết; nâng cao tính ổn định của hệ thống, bảo đảm an toàn dữ liệu và hiển thị thông tin, cam kết bảo mật nhằm tăng tỷ lệ tham gia khảo sát của người dân và doanh nghiệp.", "7119": "- Thống kê, theo dõi tiến độ khảo sát theo thời gian thực;\\n- Quản lý và phân phối phiếu khảo sát (Tạo và quản lý mã QR, đường liên kết khảo sát; theo dõi lượt truy cập, lượt hoàn thành và trạng thái của từng đợt khảo sát);\\n- Tự động tổng hợp và xuất kết quả khảo sát.", "7120": "- Làm rõ cơ chế xác thực và bảo đảm tính hợp lệ của phiếu khảo sát, tránh trường hợp một người tham gia nhiều lần nhưng vẫn bảo đảm tính ẩn danh theo yêu cầu của từng loại khảo sát.\\n- Nghiên cứu cơ chế phân bổ, quản lý và theo dõi mẫu khảo sát, bảo đảm đúng đối tượng, đúng số lượng theo từng đơn vị, địa bàn và thuận lợi trong quá trình triển khai.\\n- Làm rõ khả năng tích hợp, chia sẻ dữ liệu với các hệ thống dùng chung của Thành phố, phục vụ công tác tổng hợp, thống kê và báo cáo, hạn chế việc nhập liệu nhiều lần.", "7121": [["Cao", "Cao", "Cao"]], "7123": "Các yêu cầu trên đã được thống nhất.", "7124": "nguyenvietchinh.hn@gmail.com/0973034804", "7125": "Ngọc Hà", "7126": "ks2_ngocha", "7127": "Công chức, phòng Văn hóa - Xã hội", "7128": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "7129": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "email": "", "phone": "", "agency": "Ngọc Hà", "position": "", "full_name": "ks2_ngocha", "department": "Ngọc Hà", "organization": "Ngọc Hà"}	f	\N	f	f	2026-07-14 08:34:05.822283+00	457	21	{"sec_mrji32jc_02myx": 100, "sec_mrji3pol_08ygj": 100, "sec_mrji3pol_kjxj5": 100, "sec_mrji3pom_xwahu": 100, "sec_mrji4ctm_06kdb": 0, "sec_mrji4ctm_gtanp": 100, "sec_mrji4ctm_w2j5m": 100, "sec_mrji4zz8_b0vue": 100, "sec_mrji4zz8_eyyqa": 0, "sec_mrji4zz8_qvwvf": 100}	submitted
