1070	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-15 09:24:56.225484+00	2026-07-15 09:28:03.343071+00	187	{"7271": {"data": [[null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null]], "type": "grid"}, "7272": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "7273": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "7274": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "7275": {"data": [[null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null]], "type": "grid"}, "7276": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "7277": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "7278": "Trong quá trình triển khai điều tra xã hội học, khảo sát đo lường sự hài lòng của người dân, tổ chức (SIPAS) và khảo sát chỉ số DDCI, đơn vị gặp phải một số khó khăn, vướng mắc thực tế sau:\\nNgười dân và doanh nghiệp còn tâm lý e ngại, thờ ơ: >   * Nhiều công dân sau khi hoàn thành thủ tục hành chính thường có tâm lý muốn ra về ngay, không muốn mất thời gian dừng lại để điền phiếu khảo sát giấy hoặc quét mã QR đánh giá.\\nMột số doanh nghiệp, hộ kinh doanh trên địa bàn còn e ngại việc đánh giá thẳng thắn các mặt tồn tại của cơ quan quản lý nhà nước sẽ ảnh hưởng đến hoạt động kinh doanh sau này, dẫn đến kết quả trả lời đôi khi mang tính \\"đối phó\\" hoặc chọn phương án an toàn (mức trung bình).\\nPhương thức tiếp cận và lấy mẫu khảo sát gặp nhiều trở ngại:\\nĐịa bàn phường Ô Chợ Dừa có mật độ dân cư rất đông, biến động cư trú (tạm trú, thuê nhà) lớn. Việc đi từng ngõ, gõ từng nhà để thực hiện điều tra xã hội học theo danh sách ngẫu nhiên gặp khó khăn do người dân thường đi làm vào giờ hành chính, khó gặp trực tiếp để phỏng vấn.\\n\\nĐối tượng người cao tuổi hoặc người lao động phổ thông gặp hạn chế trong việc tiếp cận công nghệ khi thực hiện các biểu mẫu khảo sát trực tuyến trên điện thoại thông minh.\\nHạn chế về nguồn lực và công cụ hỗ trợ:\\nCán bộ đầu mối và lực lượng hỗ trợ (như Tổ công nghệ số cộng đồng) phải kiêm nhiệm nhiều nhiệm vụ chuyên môn khác tại địa phương, trong khi công tác điều tra, giải thích nghiệp vụ khảo sát đòi hỏi rất nhiều thời gian và công sức thuyết phục.\\nChưa có hệ thống phần mềm chuyên dụng hỗ trợ phân tích nhanh phản hồi theo thời gian thực (real-time). Việc thống kê dữ liệu chủ yếu vẫn thực hiện thủ công hoặc đợi kết quả tổng hợp định kỳ từ cấp trên gửi về, dẫn đến việc UBND phường khó phát hiện kịp thời các điểm nghẽn để chấn chỉnh, khắc phục ngay tại chỗ.", "7279": "Nhằm khắc phục các khó khăn trong thực tế và nâng cao chất lượng hiệu quả vận hành của hệ thống khảo sát, đánh giá trực tuyến (SIPAS), UBND phường kính đề xuất một số nội dung sau:\\nTích hợp đa kênh, đơn giản hóa giao diện khảo sát: Đề xuất thiết kế các biểu mẫu khảo sát SIPAS cực kỳ tối giản, có thể trả lời nhanh trong vòng 1 - 2 phút thông qua việc chạm chọn trên màn hình cảm ứng (Kiosk) đặt ngay tại bộ phận Một cửa, hoặc qua tin nhắn Zalo tự động sau khi hồ sơ được trả kết quả thành công.\\n\\nHỗ trợ giao diện đọc/phóng to chữ dành riêng cho đối tượng công dân là người cao tuổi khi tự thực hiện đánh giá.\\nXây dựng tính năng \\"Phân tích ý kiến phản hồi bằng AI\\": >   * Đề xuất hệ thống bổ sung công cụ tự động phân tích thái độ, phân loại các ý kiến đóng góp dạng văn bản tự do của người dân và doanh nghiệp. Việc này giúp phân nhóm nhanh các nội dung phản ánh (về thái độ cán bộ, về cơ sở vật chất, hoặc về quy trình thủ tục) để lãnh đạo phường nắm bắt và chấn chỉnh kịp thời mà không cần đọc thủ công từng phiếu.\\nCơ chế liên thông dữ liệu và đồng bộ báo cáo: >   * Đề xuất hệ thống khảo sát tự động kết xuất dữ liệu báo cáo định kỳ dưới dạng biểu đồ trực quan (Dashboard) cho cấp phường. Kết quả đo lường sự hài lòng cần được cập nhật liên tục hàng tuần/hàng tháng thay vì chờ đợi báo cáo tổng hợp cuối năm, giúp đơn vị chủ động cải thiện chỉ số CCHC.\\nChính sách hỗ trợ, khuyến khích công dân tham gia:\\nKiến nghị cấp trên có cơ chế hoặc bố trí nguồn kinh phí hỗ trợ nhỏ (ví dụ: tặng mã giảm giá dịch vụ công, hoặc hỗ trợ chi phí in ấn tài liệu tuyên truyền) nhằm khuyến khích, tạo động lực cho người dân và các doanh nghiệp tích cực tham gia các cuộc điều tra xã hội học một cách thực chất và khách quan.", "email": "", "phone": "", "agency": "Ô Chợ Dừa", "position": "", "full_name": "ks2_ochodua", "department": "Ô Chợ Dừa", "organization": "Ô Chợ Dừa"}	f	\N	f	f	2026-07-15 09:24:56.225537+00	466	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	submitted
1084	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-15 09:41:10.885814+00	2026-07-15 09:45:32.967633+00	262	{"7208": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, "Đáp ứng", null, null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null]], "type": "grid"}, "7209": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7210": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7211": {"data": [[null, null, null, null, "Không áp dụng"], [null, null, null, null, "Không áp dụng"], [null, null, null, null, "Không áp dụng"], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, null, null, null, "Không áp dụng"], [null, null, null, null, "Không áp dụng"]], "type": "grid"}, "7212": {"data": [[null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null]], "type": "grid"}, "7213": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, "Có", null], [null, null, "Không"]], "type": "grid"}, "7214": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null]], "type": "grid"}, "7215": {"data": [[null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7216": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7217": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "7218": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "7219": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "7220": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "7222": "Hệ thống công nghệ thông tin còn phân tán, nhiều phần mềm hoạt động độc lập, chưa liên thông, chia sẻ dữ liệu đồng bộ, dẫn đến phải nhập liệu nhiều lần.\\nĐội ngũ cán bộ phụ trách công nghệ thông tin chủ yếu kiêm nhiệm, thiếu nhân lực chuyên trách; việc hỗ trợ kỹ thuật, xử lý sự cố đôi khi chưa kịp thời.\\nHạ tầng công nghệ thông tin tại một số đơn vị chưa đáp ứng yêu cầu, thiết bị đã sử dụng nhiều năm, hiệu năng thấp; đường truyền mạng đôi lúc chưa ổn định.\\nMột số hệ thống thường xuyên nâng cấp, thay đổi chức năng nhưng tài liệu hướng dẫn và công tác tập huấn chưa theo kịp, gây khó khăn trong quá trình khai thác, sử dụng.\\nChưa có nền tảng giám sát tập trung để theo dõi tình trạng hoạt động của các hệ thống, cảnh báo sự cố và đánh giá hiệu quả khai thác.\\nKinh phí dành cho đầu tư, nâng cấp hạ tầng, bản quyền phần mềm và bảo đảm an toàn thông tin còn hạn chế, chưa đáp ứng yêu cầu chuyển đổi số trong giai đoạn hiện nay.", "7223": "Xây dựng hệ thống công nghệ thông tin thống nhất, đồng bộ, có khả năng liên thông, chia sẻ dữ liệu với các hệ thống dùng chung của Thành phố, hạn chế nhập liệu trùng lặp.\\nBổ sung Dashboard điều hành phục vụ lãnh đạo theo dõi tiến độ, kết quả thực hiện nhiệm vụ và các chỉ số theo thời gian thực.\\nTăng cường ứng dụng AI trong tổng hợp báo cáo, phân tích dữ liệu, cảnh báo nhiệm vụ chậm tiến độ và hỗ trợ ra quyết định.\\nHoàn thiện chức năng quản lý hồ sơ, minh chứng điện tử, tự động tổng hợp báo cáo, thống kê và xuất dữ liệu theo biểu mẫu quy định.\\nNâng cao hiệu năng, tính ổn định và an toàn thông tin của hệ thống; hỗ trợ truy cập thuận tiện trên cả máy tính và thiết bị di động.\\nTăng cường công tác hỗ trợ kỹ thuật, hướng dẫn sử dụng và đào tạo cho cán bộ trong quá trình khai thác, vận hành hệ thống.\\nThường xuyên cập nhật, nâng cấp hệ thống trên cơ sở tiếp thu ý kiến của các đơn vị sử dụng, bảo đảm đáp ứng yêu cầu quản lý, điều hành và chuyển đổi số trong tình hình mới.", "7224": {"data": [[null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"], [null, null, null, "Suối Hai"]], "type": "grid"}, "email": "", "phone": "", "agency": "Suối Hai", "position": "", "full_name": "ks2_suoihai", "department": "Suối Hai", "organization": "Suối Hai"}	f	\N	f	f	2026-07-15 09:41:10.885874+00	571	18	{"sec_mrd51u8k_s7xvx": 0, "sec_mrd52i20_bxs8q": 100, "sec_mrd589py_n4ccb": 100, "sec_mrd58wv7_h9r0m": 100, "sec_mrd5h8uk_83ljt": 100, "sec_mrd5h8uk_lb1ld": 100, "sec_mrd5h8uk_q8t9f": 100, "sec_mrd5h8uk_zlvj1": 100, "sec_mrd5h8uk_znbx8": 100, "sec_mrd5hvzu_sb784": 100, "sec_mrd5hvzv_7jcz3": 100, "sec_mrd5hvzv_a4wue": 100, "sec_mrd5hvzv_ae5ra": 100, "sec_mrd5hvzv_vsvm8": 100, "sec_mrd5hvzv_ztdcy": 100, "sec_mrd5ij53_k401z": 100, "sec_mrd5ij53_lxnd3": 100}	submitted
